		slog.Int64("amount", cmd.Amount),
		slog.String("currency", cmd.Currency),
	)

	logger.Info("processing deposit request via provider")

	result, err := u.provider.Charge(ctx, cmd)
	if err != nil {
		logger.Error("provider charge error", "error", err)
