	if !ok {
		return nil, ErrWalletNotFound
	}

	if w.Balance < amount {
		return nil, ErrInsufficientFunds
	}

	balanceBefore := w.Balance
	balanceAfter := w.Balance - amount

	w.Balance = balanceAfter
	w.UpdatedAt = time.Now().UTC()

	m.idCounter++
