	OutcomeFailed      SagaOutcome = "failed"
	OutcomeCompensated SagaOutcome = "compensated"
)

var legalSagaTransitions = map[SagaStatus]map[SagaStatus]bool{
	StatusCreated: {
		StatusRunning: true,
	},
	StatusRunning: {
		StatusCompleted:              true,
